{
  "summary": "The paper proposes SAGE, a sensitivity-guided adaptive learning rate schedule that dynamically adjusts per-parameter learning rates based on parameter sensitivity and its local temporal variation to reduce redundancy and improve generalization in large models. Extensive experiments across NLP, NMT, and vision tasks demonstrate consistent performance gains, especially in low-data regimes, and show that SAGE complements existing optimizers and regularization methods.",
  "strengths": [
    {
      "point": "Novel adaptive learning rate schedule leveraging parameter sensitivity and its uncertainty",
      "evidence": "SAGE adjusts learning rates based on the magnitude of parameter-gradient product and its local temporal variation, promoting balanced training of all parameters."
    },
    {
      "point": "Comprehensive empirical evaluation across multiple domains and model types",
      "evidence": "Experiments on GLUE benchmarks with BERT and RoBERTa, NMT tasks with Transformer, and image classification with ViT show consistent improvements."
    },
    {
      "point": "Demonstrated complementarity with existing optimizers and regularization methods",
      "evidence": "SAGE integrates with SGD, Adam, Adamax and further improves performance when combined with SMART regularization."
    },
    {
      "point": "Insightful analysis linking sensitivity distribution, pruning performance, and generalization",
      "evidence": "The paper shows that SAGE leads to more reliable sensitivity measures, better pruning outcomes, and smoother decision boundaries."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to closely related adaptive learning rate methods",
      "evidence": "No empirical or conceptual comparison to methods like AdaBound, RAdam, or second-order optimizers limits understanding of SAGE's relative novelty."
    },
    {
      "point": "Insufficient justification and ablation of the sensitivity definition and components",
      "evidence": "The choice of sensitivity as parameter-gradient product magnitude is not well motivated, and no ablation isolates the effects of sensitivity versus local temporal variation."
    },
    {
      "point": "Unclear hyperparameter sensitivity and stability",
      "evidence": "The paper does not report how performance varies with hyperparameters controlling moving averages or learning rate scaling, leaving robustness uncertain."
    },
    {
      "point": "Potential fairness issues in baseline comparisons",
      "evidence": "Baselines appear to use default learning rates without clear tuning or matched learning rate schedules, raising concerns about apples-to-apples comparisons."
    },
    {
      "point": "Limited evaluation metrics and lack of statistical significance testing",
      "evidence": "Metrics focus on accuracy, BLEU, and task averages without calibration or robustness measures; no confidence intervals or significance tests are provided."
    },
    {
      "point": "Reproducibility concerns due to missing implementation details and code",
      "evidence": "Details on efficient computation of sensitivity and temporal variation at scale are lacking, and no code or full hyperparameter settings are released."
    },
    {
      "point": "Ambiguity in the definition and computation of local temporal variation",
      "evidence": "The moving average window, decay factor choice, and normalization of temporal variation are not clearly specified."
    },
    {
      "point": "Limited discussion on computational overhead and scalability",
      "evidence": "Quantitative measurements of additional computation time or memory usage introduced by SAGE, especially on large models, are missing."
    },
    {
      "point": "Limited generalizability evaluation beyond Transformers and ViT",
      "evidence": "No experiments on CNNs, RNNs, or other architectures, nor on transfer or continual learning scenarios."
    },
    {
      "point": "No discussion on potential overfitting or limitations in low-data or noisy regimes",
      "evidence": "Largest gains are on small datasets but possible overfitting or failure modes in such regimes are not analyzed."
    }
  ],
  "questions": [
    {
      "question": "How does SAGE compare empirically and conceptually to other adaptive learning rate methods like AdaBound or RAdam?",
      "motivation": "Understanding relative novelty and advantages is crucial for assessing the contribution."
    },
    {
      "question": "What is the sensitivity of SAGE's performance to its hyperparameters and how stable is it across different settings?",
      "motivation": "Robustness and ease of use depend on hyperparameter sensitivity."
    },
    {
      "question": "Can the authors provide more detailed implementation specifics and release code to facilitate reproducibility?",
      "motivation": "Reproducibility is essential for adoption and further research."
    },
    {
      "question": "What is the computational overhead of SAGE in terms of runtime and memory, especially for very large models?",
      "motivation": "Practical applicability depends on scalability and efficiency."
    },
    {
      "question": "How does SAGE perform on architectures beyond Transformers and ViT, and in transfer or continual learning scenarios?",
      "motivation": "Broader applicability would strengthen the impact claims."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
